"bottom\":\"15\",\"left\":\"15\",\"isLinked\":false},\"_border_border\":\"solid\",\"_border_width\":{\"unit\":\"px\",\"top\":\"15\",\"right\":\"5\",\"bottom\":\"5\",\"left\":\"5\",\"isLinked\":false},\"_border_color\":\"#00F7F7\",\"_border_radius\":{\"unit\":\"px\",\"top\":\"15\",\"right\":\"15\",\"bottom\":\"15\",\"left\":\"15\",\"isLinked\":true},\"global_text_color\":\"#000000\",\"heading_text_color\":\"#000000\",\"label_color\":\"#000000\",\"input_color\":\"#000000\",\"buttons_typography_typography\":\"custom\",\"buttons_typography_font_family\":\"Hind Siliguri\",\"buttons_typography_font_size\":{\"unit\":\"px\",\"size\":25,\"sizes\":[]},\"buttons_typography_font_weight\":\"600\",\"button_text_color\":\"#FFFFFF\",\"btn_background_color_background\":\"classic\",\"btn_background_color_color\":\"#00B22C\",\"btn_hover_color\":\"#00B22C\",\"button_background_hover_color_background\":\"classic\",\"button_background_hover_color_color\":\"#FFFFFF\",\"payment_section_text_color\":\"#000000\",\"payment_section_desc_color\":\"#000000\",\"product_text_color\":\"#000000\",\"_element_id\":\"order-form\",\"buttons_typography_font_size_mobile\":{\"unit\":\"px\",\"size\":16,\"sizes\":[]},\"button_box_shadow_box_shadow_type\":\"yes\",\"button_box_shadow_box_shadow\":{\"horizontal\":2,\"vertical\":2,\"blur\":10,\"spread\":0,\"color\":\"#000000\"},\"product_options_images\":\"yes\",\"global_typography_typography\":\"custom\",\"global_typography_font_family\":\"Hind Siliguri\",\"global_typography_font_size\":{\"unit\":\"px\",\"size\":16,\"sizes\":[]},\"_background_background\":\"classic\",\"custom_css\":\"\\/* \\r\\n  CartFluts Checkout Form Styling \\r\\n  Note: If you want to target ONLY this section, replace \\\".wcf-embed-checkout-form\\\" \\r\\n  with your Elementor section CSS ID (e.g., #my-checkout-section) at the top of each block.\\r\\n*\\/\\r\\n\\r\\n\\/* 1. Input Fields & Textareas *\\/\\r\\n.wcf-embed-checkout-form .form-row input[type=\\\"text\\\"],\\r\\n.wcf-embed-checkout-form .form-row input[type=\\\"email\\\"],\\r\\n.wcf-embed-checkout-form .form-row input[type=\\\"tel\\\"],\\r\\n.wcf-embed-checkout-form .form-row input[type=\\\"password\\\"],\\r\\n.wcf-embed-checkout-form .form-row textarea,\\r\\n.wcf-embed-checkout-form .form-row select {\\r\\n    width: 100% !important;\\r\\n    padding: 14px 16px !important;\\r\\n    border: 1px solid #e0e0e0 !important;\\r\\n    border-radius: 8px !important;\\r\\n    background-color: #ffffff !important;\\r\\n    font-size: 16px !important;\\r\\n    color: #333333 !important;\\r\\n    transition: all 0.3s ease-in-out !important;\\r\\n    box-sizing: border-box !important;\\r\\n}\\r\\n\\r\\n\\/* 2. Input Focus States (When clicking a field) *\\/\\r\\n.wcf-embed-checkout-form .form-row input:focus,\\r\\n.wcf-embed-checkout-form .form-row textarea:focus,\\r\\n.wcf-embed-checkout-form .form-row select:focus {\\r\\n    border-color: #007cba !important; \\/* Change to your brand color *\\/\\r\\n    background-color: #f9fbff !important;\\r\\n    box-shadow: 0 0 0 3px rgba(0, 124, 186, 0.1) !important;\\r\\n    outline: none !important;\\r\\n}\\r\\n\\r\\n\\/* 3. Labels *\\/\\r\\n.wcf-embed-checkout-form .form-row label {\\r\\n    font-weight: 600 !important;\\r\\n    color: #444444 !important;\\r\\n    margin-bottom: 8px !important;\\r\\n    font-size: 14px !important;\\r\\n    display: block !important;\\r\\n}\\r\\n\\r\\n\\/* Required Asterisk Styling *\\/\\r\\n.wcf-embed-checkout-form .form-row label .required,\\r\\n.wcf-embed-checkout-form .form-row .required {\\r\\n    color: #e2401c !important;\\r\\n    border: none !important;\\r\\n    text-decoration: none !important;\\r\\n}\\r\\n\\r\\n\\/* 4. Spacing between form fields *\\/\\r\\n.wcf-embed-checkout-form .form-row,\\r\\n.wcf-embed-checkout-form .woocommerce-billing-fields .form-row {\\r\\n    margin-bottom: 20px !important;\\r\\n}\\r\\n\\r\\n\\/* 5. The \\\"Place Order\\\" \\/ Checkout Button *\\/\\r\\n.wcf-embed-checkout-form #place_order,\\r\\n.wcf-embed-checkout-form .wcf-checkout-submit-button button {\\r\\n    background-color: #007cba !important; \\/* Change to your brand color *\\/\\r\\n    color: #ffffff !important;\\r\\n    font-size: 18px !important;\\r\\n    font-weight: 700 !important;\\r\\n    padding: 18px 24px !important;\\r\\n    border-radius: 8px !important;\\r\\n    border: none !important;\\r\\n    width: 100% !important;\\r\\n    text-transform: uppercase !important;\\r\\n    letter-spacing: 1px !important;\\r\\n    cursor: pointer !important;\\r\\n    transition: background-color 0.3s ease, transform 0.2s ease !important;\\r\\n    box-shadow: 0 4px 15px rgba(0, 124, 186, 0.2) !important;\\r\\n}\\r\\n\\r\\n\\/* Button Hover State *\\/\\r\\n.wcf-embed-checkout-form #place_order:hover,\\r\\n.wcf-embed-checkout-form .wcf-checkout-submit-button button:hover {\\r\\n    background-color: #005a87 !important; \\/* Darker shade of your brand color *\\/\\r\\n    transform: translateY(-2px) !important;\\r\\n    box-shadow: 0 6px 20px rgba(0, 124, 186, 0.3) !important;\\r\\n}\\r\\n\\r\\n\\/* Button Active State *\\/\\r\\n.wcf-embed-checkout-form #place_order:active {\\r\\n    transform: translateY(0) !important;\\r\\n}\\r\\n\\r\\n\\/* 6. Order Summary Table *\\/\\r\\n.wcf-embed-checkout-form .woocommerce-checkout-review-order-table {\\r\\n    width: 100% !important;\\r\\n    border-collapse: collapse !important;\\r\\n    margin-bottom: 20px !important;\\r\\n}\\r\\n\\r\\n.wcf-embed-checkout-form .woocommerce-checkout-review-order-table th,\\r\\n.wcf-embed-checkout-form .woocommerce-checkout-review-order-table td {\\r\\n    padding: 14px 12px !important;\\r\\n    border-bottom: 1px solid #f0f0f0 !important;\\r\\n    text-align: left !important;\\r\\n}\\r\\n\\r\\n.wcf-embed-checkout-form .woocommerce-checkout-review-order-table thead {\\r\\n    background-color: #f9f9f9 !important;\\r\\n}\\r\\n\\r\\n\\/* 7. Coupon Code Input & Button *\\/\\r\\n.wcf-embed-checkout-form .coupon-form input,\\r\\n.wcf-embed-checkout-form #coupon_code {\\r\\n    padding: 14px 16px !important;\\r\\n    border-radius: 8px 0 0 8px !important;\\r\\n    border: 1px solid #e0e0e0 !important;\\r\\n    border-right: none !important;\\r\\n    flex: 1 !important;\\r\\n}\\r\\n\\r\\n.wcf-embed-checkout-form .coupon-form button,\\r\\n.wcf-embed-checkout-form .checkout_coupon button {\\r\\n    padding: 14px 24px !important;\\r\\n    border-radius: 0 8px 8px 0 !important;\\r\\n    background-color: #333333 !important;\\r\\n    color: #ffffff !important;\\r\\n    border: none !important;\\r\\n    font-weight: 600 !important;\\r\\n    cursor: pointer !important;\\r\\n}\\r\\n\\r\\n\\/* 8. Trust Badges \\/ Checkout Totals Box *\\/\\r\\n.wcf-embed-checkout-form .cart_totals,\\r\\n.wcf-embed-checkout-form .checkout-review-order-table-wrapper {\\r\\n    background: #ffffff !important;\\r\\n    padding: 25px !important;\\r\\n    border-radius: 12px !important;\\r\\n    border: 1px solid #eeeeee !important;\\r\\n    box-shadow: 0 10px 30px rgba(0,0,0,0.03) !important;\\r\\n}\\r\\n\\r\\n\\/* 9. Mobile Responsiveness *\\/\\r\\n@media only screen and (max-width: 768px) {\\r\\n    .wcf-embed-checkout-form .form-row-first,\\r\\n    .wcf-embed-checkout-form .form-row-last {\\r\\n        width: 100% !important;\\r\\n        float: none !important;\\r\\n    }\\r\\n    \\r\\n    .wcf-embed-checkout-form #place_order {\\r\\n        font-size: 16px !important;\\r\\n        padding: 16px 20px !important;\\r\\n    }\\r\\n}\"},\"elements\":[],\"widgetType\":\"checkout-form\"}],\"isInner\":false}],\"isInner\":false},{\"id\":\"5d94ef44\",\"elType\":\"section\",\"settings\":{\"background_background\":\"classic\",\"background_color\":\"#54595F0F\",\"padding\":{\"unit\":\"px\",\"top\":\"12\",\"right\":\"20\",\"bottom\":\"12\",\"left\":\"20\",\"isLinked\":false},\"padding_mobile\":{\"unit\":\"px\",\"top\":\"10\",\"right\":\"10\",\"bottom\":\"10\",\"left\":\"10\",\"isLinked\":true},\"__globals__\":{\"background_color\"