(24, 1, '2026-06-27 19:23:20', '2026-06-27 19:23:20', '<form name=\"checkout\" method=\"post\" action=\"https://ninetys.store/checkout/\" enctype=\"multipart/form-data\">\n			<!--open container-->\n				<!--open column-1-->\n				<wc-order-attribution-inputs></wc-order-attribution-inputs>\n		<h3 id=\"billing_fields_heading\">Billing Details</h3>\n		<p id=\"billing_first_name_field\" data-priority=\"10\"><label for=\"billing_first_name\">First Name&nbsp;*</label><input type=\"text\" name=\"billing_first_name\" id=\"billing_first_name\" placeholder=\"First Name\"  value=\"\" aria-required=\"true\" autocomplete=\"section-billing billing given-name\" /></p><p id=\"billing_last_name_field\" data-priority=\"20\"><label for=\"billing_last_name\">Last Name&nbsp;*</label><input type=\"text\" name=\"billing_last_name\" id=\"billing_last_name\" placeholder=\"Last Name\"  value=\"\" aria-required=\"true\" autocomplete=\"section-billing billing family-name\" /></p><p id=\"billing_country_field\" data-priority=\"40\"><label for=\"billing_country\">Country / Region&nbsp;*</label><select name=\"billing_country\" id=\"billing_country\" aria-required=\"true\" autocomplete=\"section-billing billing country\"><option value=\"BD\" selected>Bangladesh</option></select></p><p id=\"billing_address_1_field\" data-priority=\"50\"><label for=\"billing_address_1\">Street address&nbsp;*</label><input type=\"text\" name=\"billing_address_1\" id=\"billing_address_1\" placeholder=\"House number and street name&nbsp;*\"  value=\"\" aria-required=\"true\" autocomplete=\"section-billing billing address-line1\" /></p><p id=\"billing_address_2_field\" data-priority=\"60\"><label for=\"billing_address_2\">Apartment, suite, unit, etc.&nbsp;(optional)</label><input type=\"text\" name=\"billing_address_2\" id=\"billing_address_2\" placeholder=\"Apartment, suite, unit, etc. (optional)\"  value=\"\" autocomplete=\"section-billing billing address-line2\" /></p><p id=\"billing_city_field\" data-priority=\"70\"><label for=\"billing_city\">Town / City&nbsp;*</label><input type=\"text\" name=\"billing_city\" id=\"billing_city\" placeholder=\"Town / City&nbsp;*\"  value=\"\" aria-required=\"true\" autocomplete=\"section-billing billing address-level2\" /></p><p id=\"billing_state_field\" data-priority=\"80\"><label for=\"billing_state\">District&nbsp;*</label><select name=\"billing_state\" id=\"billing_state\" aria-required=\"true\" autocomplete=\"section-billing billing address-level1\" data-placeholder=\"District&nbsp;*\"  data-input-classes=\"\" data-label=\"District\">\n						<option value=\"\">Select an option&hellip;</option><option value=\"BD-05\" >Bagerhat</option><option value=\"BD-01\" >Bandarban</option><option value=\"BD-02\" >Barguna</option><option value=\"BD-06\" >Barishal</option><option value=\"BD-07\" >Bhola</option><option value=\"BD-03\" >Bogura</option><option value=\"BD-04\" >Brahmanbaria</option><option value=\"BD-09\" >Chandpur</option><option value=\"BD-10\" >Chattogram</option><option value=\"BD-12\" >Chuadanga</option><option value=\"BD-11\" >Cox&#039;s Bazar</option><option value=\"BD-08\" >Cumilla</option><option value=\"BD-13\"  selected=\'selected\'>Dhaka</option><option value=\"BD-14\" >Dinajpur</option><option value=\"BD-15\" >Faridpur </option><option value=\"BD-16\" >Feni</option><option value=\"BD-19\" >Gaibandha</option><option value=\"BD-18\" >Gazipur</option><option value=\"BD-17\" >Gopalganj</option><option value=\"BD-20\" >Habiganj</option><option value=\"BD-21\" >Jamalpur</option><option value=\"BD-22\" >Jashore</option><option value=\"BD-25\" >Jhalokati</option><option value=\"BD-23\" >Jhenaidah</option><option value=\"BD-24\" >Joypurhat</option><option value=\"BD-29\" >Khagrachhari</option><option value=\"BD-27\" >Khulna</option><option value=\"BD-26\" >Kishoreganj</option><option value=\"BD-28\" >Kurigram</option><option value=\"BD-30\" >Kushtia</option><option value=\"BD-31\" >Lakshmipur</option><option value=\"BD-32\" >Lalmonirhat