(39, 1, '2026-06-27 19:40:46', '2026-06-27 19:40:46', '<img src=\"https://ninetys.store/wp-content/plugins/elementor/assets/images/placeholder.png\" title=\"\" alt=\"\" loading=\"lazy\" />																<h2>চিংড়ি বালাচাও</h2>					<h2>“চিংড়ি বালাচাও” খুবই সুস্বাদু ও মুখরোচক একটি খাবার। নামটা যেমন অন্যরকম, খেতেও অসম্ভব মজাদার। বালাচাও হচ্ছে এক প্রকার রেডি টু ইট ফুড, যা মুলত চিংড়ি, পেয়াজ , রসুন, শুকনো মরিচ ও মশলার একটি মিশ্রণ। বালাচাও হচ্ছে কক্সবাজার ও চট্টগ্রামের একটি জনপ্রিয় ঐতিহ্যবাহী খাবার।</h2>					<h2>হোম মেইড এবং রেডি টু ইট ফুড</h2>										<a href=\"#order-form\">\n				<svg aria-hidden=\"true\" viewBox=\"0 0 512 512\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M504 256C504 119 393 8 256 8S8 119 8 256s111 248 248 248 248-111 248-248zm-448 0c0-110.5 89.5-200 200-200s200 89.5 200 200-89.5 200-200 200S56 366.5 56 256zm72 20v-40c0-6.6 5.4-12 12-12h116v-67c0-10.7 12.9-16 20.5-8.5l99 99c4.7 4.7 4.7 12.3 0 17l-99 99c-7.6 7.6-20.5 2.2-20.5-8.5v-67H140c-6.6 0-12-5.4-12-12z\"></path></svg>			\n									অর্ডার করতে ক্লিক করুন\n					</a>\n																			<img src=\"https://ninetys.store/wp-content/plugins/elementor/assets/images/placeholder.png\" title=\"\" alt=\"\" loading=\"lazy\" />																<h2>কি কি উপাদানে তৈরি?</h2>															<img src=\"https://ninetys.store/wp-content/plugins/elementor/assets/images/placeholder.png\" title=\"\" alt=\"\" loading=\"lazy\" />																<h2>চিংড়ি শুটকি</h2>															<img src=\"https://ninetys.store/wp-content/plugins/elementor/assets/images/placeholder.png\" title=\"\" alt=\"\" loading=\"lazy\" />																<h2>পেঁয়াজ বেরেস্তা</h2>															<img src=\"https://ninetys.store/wp-content/plugins/elementor/assets/images/placeholder.png\" title=\"\" alt=\"\" loading=\"lazy\" />																<h2>রসুন ভাজা\n</h2>															<img src=\"https://ninetys.store/wp-content/plugins/elementor/assets/images/placeholder.png\" title=\"\" alt=\"\" loading=\"lazy\" />																<h2>মরিচের গুঁড়া</h2>															<img src=\"https://ninetys.store/wp-content/plugins/elementor/assets/images/placeholder.png\" title=\"\" alt=\"\" loading=\"lazy\" />																<h2>সিক্রেট মশলা</h2>					<h2>যেভাবে খাওয়া যায়</h2>							<ul>\n							<li>\n							<svg aria-hidden=\"true\" viewBox=\"0 0 512 512\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M173.898 439.404l-166.4-166.4c-9.997-9.997-9.997-26.206 0-36.204l36.203-36.204c9.997-9.998 26.207-9.998 36.204 0L192 312.69 432.095 72.596c9.997-9.997 26.207-9.997 36.204 0l36.203 36.204c9.997 9.997 9.997 26.206 0 36.204l-294.4 294.401c-9.998 9.997-26.207 9.997-36.204-.001z\"></path></svg>						\n										মুড়ি মাখা বা মুড়ি ভর্তার সাথে।\n									</li>\n								<li>\n							<svg aria-hidden=\"true\" viewBox=\"0 0 512 512\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M173.898 439.404l-166.4-166.4c-9.997-9.997-9.997-26.206 0-36.204l36.203-36.204c9.997-9.998 26.207-9.998 36.204 0L192 312.69 432.095 72.596c9.997-9.997 26.207-9.997 36.204 0l36.203 36.204c9.997 9.997 9.997 26.206 0 36.204l-294.4 294.401c-9.998 9.997-26.207 9.997-36.204-.001z\"></path></svg>						\n										আলু ভর্তার সাথে মিশিয়ে।\n									</li>\n								<li>\n							<svg aria-hidden=\"true\" viewBox=\"0 0 512 512\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M173.898 439.404l-166.4-166.4c-9.997-9.997-9.997-26.206 0-36.204l36.203-36.204c9.997-9.998 26.207-9.998 36.204 0L192 312.69 432.095 72.596c9.997-9.997 26.207-9.997 36.204 0l36.203 36.204c9.997 9.997 9.997 26.206 0 36.204l-294.4 294.401c-9.998 9.997-26.207 9.997-36.204-.001z\"></path></svg>						\n										বেগুন ভর্তার সাথে মিশিয়ে।\n									</li>\n								<li>\n							<svg aria-hidden=\"true\" viewBox=\"0 0 512 512\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M173.898 439.404l-166.4-166.4c-9.997-9.997-9.997-26.206 0-36.204l36.203-36.204c9.997-9.998 26.207-9.998 36.204 0L192 312.69 432.095 72.596c9.997-9.997 26.207-9.997 36.204 0l36.203 36.204c9.997 9.997 9.997 26.206 0 36.204l-294.4 294.401c-9.998 9.997-26.207 9.997-36.204-.001z\"></path></svg>						\n										গরম ধোয়া ওঠা সাদা ভাতের সাথে।\n									</li>\n								<li>\n							<svg aria-hidden=\"true\" viewBox=\"0 0 512 512\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M173.898 439.404l-166.4-166.4c-9.997-9.997-9.997-26.206 0-36.204l36.203-36.204c9.997-9.998 26.207-9.998 36.204 0L192 312.69 432.095 72.596c9.997-9.997 26.207-9.997 36.204 0l36.203 36.204c9.997 9.997 9.997 26.206 0 36.204l-294.4 294.401c-9.998 9.997-26.207 9.997-36.204-.001z\"></path></svg>						\n										চানাচুরের মতো সরাসরি।\n									</li>\n								<li>\n							<svg aria-hidden=\"true\" viewBox=\"0 0 512 512\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M173.898 439.404l-166.4-166.4c-9.997-9.997-9.997-26.206 0-36.204l36.203-36.204c9.997-9.998 26.207-9.998 36.204 0L192 312.69 432.095 72.596c9.997-9.997 26.207-9.997 36.204 0l36.203 36.204c9.997 9.997 9.997 26.206 0 36.204l-294.4 294.401c-9.998 9.997-26.207 9.997-36.204-.001z\"></path></svg>						\n										গরম গরম খুদের ভাতের সাথে।\n									</li>\n								<li>\n							<svg aria-hidden=\"true\" viewBox=\"0 0 512 512\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M173.898 439.404l-166.4-166.4c-9.997-9.997-9.997-26.206 0-36.204l36.203-36.204c9.997-9.998 26.207-9.998 36.204 0L192 312.69 432.095 72.596c9.997-9.997 26.207-9.997 36.204 0l36.203 36.204c9.997 9.997 9.997 26.206 0 36.204l-294.4 294.401c-9.998 9.997-26.207 9.997-36.204-.001z\"></path></svg>						\n										ভূনা খিচুড়ি ও পোলাওয়ের সাথে।\n									</li>\n						</ul>\n																	<img src=\"https://ninetys.store/wp-content/plugins/elementor/assets/images/placeholder.png\" title=\"\" alt=\"\" loading=\"lazy\" />																					<a href=\"#order-form\">\n				<svg aria-hidden=\"true\" viewBox=\"0 0 512 512\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M504 256C504 119 393 8 256 8S8 119 8 256s111 248 248 248 248-111 248-248zm-448 0c0-110.5 89.5-200 200-200s200 89.5 200 200-89.5 200-200 200S56 366.5 56 256zm72 20v-40c0-6.6 5.4-12 12-12h116v-67c0-10.7 12.9-16 20.5-8.5l99 99c4.7 4.7 4.7 12.3 0 17l-99 99c-7.6 7.6-20.5 2.2-20.5-8.5v-67H140c-6.6 0-12-5.4-12-12z\"></path></svg>			\n									অর্ডার করতে ক্লিক করুন\n					</a>\n									<h2>৫০০ গ্রাম এর পূর্বমূল্য ৯৫০ এখন ছাড়ে ৮০০ টাকা</h2>							\n							<h2>১ কেজি এর পূর্বমূল্য ১৮০০ এখন ছাড়ে ১৫৫০ টাকা</h2>					<h2>আমাদের থেকে কেন নিবেন ?</h2>															<img src=\"https://ninetys.store/wp-content/plugins/elementor/assets/images/placeholder.png\" title=\"\" alt=\"\" loading=\"lazy\" />																<h2>অভিজ্ঞ বাবুর্চির ফর্মুলায় তৈরি</h2>															<img src=\"https://ninetys.store/wp-content/plugins/elementor/assets/images/placeholder.png\" title=\"\" alt=\"\" loading=\"lazy\" />																<h2>হোমমেইড প্রক্রিয়ায় স্বাস্থ্যসম্মত ভাবে তৈরি</h2>															<img src=\"https://ninetys.store/wp-content/plugins/elementor/assets/images/placeholder.png\" title=\"\" alt=\"\" loading=\"lazy\" />																<h2>বাছাইকৃত সম্পূর্ণ বালুমুক্ত চিংড়ি শুটকি</h2>															<img src=\"https://ninetys.store/wp-content/plugins/elementor/assets/images/placeholder.png\" title=\"\" alt=\"\" loading=\"lazy\" />																<h2>অরিজিনাল বালাচাও এর স্বাদ</h2>					<h2>কাস্টমার রিভিউ</h2>					অর্ডার করতে নিচের ফর্মটি পূরণ করুন					<h2>অর্ডার করতে এক টাকাও অগ্রিম দিতে হবে না। প্রোডাক্ট হাতে পেয়ে চেক করে টাকা পরিশোধ করবেন। সারাদেশে ক্যাশ অন ডেলিভারি দেয়া হয়।</h2>				\n<!-- CHECKOUT SHORTCODE -->\n<form name=\"checkout\" method=\"post\" action=\"https://ninetys.store/checkout/\" enctype=\"multipart/form-data\">\n	<h3 id=\"your_products_heading\"> Your Products </h3>\n	<input type=\"checkbox\"\n	name=\"wcf-multiple-sel\"\n	value=\"43\"  >\n	<img width=\"300\" height=\"300\" src=\"https://ninetys.store/wp-content/uploads/2026/06/Untitled-design-300x300.png\" alt=\"Saree Combo - Merun\" />\nSaree ComboColor: Merun,\n<a href=\"#\" data-product=\"18\" data-variation=\"43\">\n	Choose a Variation</a>\n		&minus;\n		<input autocomplete=\"off\" type=\"number\" value=\"1\" step=\"1\" min=\"1\" name=\"wcf_qty_selection\" placeholder=\"1\" data-sale-limit=\"false\"  title=\"\"  >\n		&plus;\n	1,290&#2547;&nbsp;\n				<wc-order-attribution-inputs></wc-order-attribution-inputs>\n		<h3 id=\"billing_fields_heading\">Billing details</h3>\n		<p id=\"billing_first_name_field\" data-priority=\"10\"><label for=\"billing_first_name\">Full Name&nbsp;*</label><input type=\"text\" name=\"billing_first_name\" id=\"billing_first_name\" placeholder=\"আপনার নাম\"  value=\"\" aria-required=\"true\" autocomplete=\"section-billing billing given-name\" /></p><p id=\"billing_address_1_field\" data-priority=\"40\"><label for=\"billing_address_1\">Full Address&nbsp;*</label><input type=\"text\" name=\"billing_address_1\" id=\"billing_address_1\" placeholder=\"আপনার ঠিকানা\"  value=\"\" aria-required=\"true\" autocomplete=\"section-billing billing address-line1\" /></p><p id=\"billing_phone_field\" data-priority=\"90\"><label for=\"billing_phone\">Phone Number&nbsp;*</label><input type=\"tel\" name=\"billing_phone\" id=\"billing_phone\" placeholder=\"আপনার নাম্বার\"  value=\"\" aria-required=\"true\" autocomplete=\"section-billing billing tel\" /></p><p id=\"billing_whatsapp_field\" data-priority=\"100\"><label for=\"billing_whatsapp\">WhatsApp&nbsp;*</label><textarea name=\"billing_whatsapp\" id=\"billing_whatsapp\" placeholder=\"আপনার হোয়াটসঅ্যাপ\"  rows=\"2\" cols=\"5\"aria-required=\"true\"></textarea></p><p id=\"billing_email_field\" data-priority=\"110\"><label for=\"billing_email\">Email address&nbsp;*</label><input type=\"email\" name=\"billing_email\" id=\"billing_email\" placeholder=\"আপনার ইমেইল\"  value=\"admin@ninetys.store\" aria-required=\"true\" autocomplete=\"section-billing billing email\" /></p>	\n	<wc-order-attribution-inputs></wc-order-attribution-inputs>\n				<wc-order-attribution-inputs></wc-order-attribution-inputs>\n	<wc-order-attribution-inputs></wc-order-attribution-inputs><input type=\"hidden\" name=\"_wcf_flow_id\" value=\"38\"><input type=\"hidden\" name=\"_wcf_checkout_id\" value=\"39\">\n		<wc-order-attribution-inputs></wc-order-attribution-inputs>\n		<h3>Shipping</h3>\n							<ul id=\"shipping_method\">\n											<li>\n							<input type=\"radio\" name=\"shipping_method[0]\" data-index=\"0\" id=\"wcf_shipping_method_0_flat_rate2\" value=\"flat_rate:2\"  /><label for=\"wcf_shipping_method_0_flat_rate2\">ঢাকার ভিতরে: <bdi>80&#2547;&nbsp;</bdi></label>						</li>\n											<li>\n							<input type=\"radio\" name=\"shipping_method[0]\" data-index=\"0\" id=\"wcf_shipping_method_0_flat_rate3\" value=\"flat_rate:3\"  checked=\'checked\' /><label for=\"wcf_shipping_method_0_flat_rate3\">ঢাকার বাহিরে: <bdi>130&#2547;&nbsp;</bdi></label>						</li>\n									</ul>\n		<h3 id=\"order_review_heading\">Your order</h3>\n			<table data-update-time=\"1782597816\">\n	<thead>\n		<tr>\n			<th>Product</th>\n			<th>Subtotal</th>\n		</tr>\n	</thead>\n	<tbody>\n						<tr>\n					<td>\n						Saree Combo - Merun&nbsp;						 <strong>&times;&nbsp;1</strong>											</td>\n					<td>\n						<bdi>1,290&#2547;&nbsp;</bdi>					</td>\n				</tr>\n					</tbody>\n	<tfoot>\n				<tr>\n			<th>Subtotal</th>\n			<td><bdi>1,290&#2547;&nbsp;</bdi></td>\n		</tr>\n						<tr>\n	<th>Shipment</th>\n	<td data-title=\"Shipment\">\n					<ul id=\"shipping_method\">\n									<li>\n						<input type=\"radio\" name=\"shipping_method[0]\" data-index=\"0\" id=\"shipping_method_0_flat_rate2\" value=\"flat_rate:2\"  /><label for=\"shipping_method_0_flat_rate2\">ঢাকার ভিতরে: <bdi>80&#2547;&nbsp;</bdi></label>					</li>\n									<li>\n						<input type=\"radio\" name=\"shipping_method[0]\" data-index=\"0\" id=\"shipping_method_0_flat_rate3\" value=\"flat_rate:3\"  checked=\'checked\' /><label for=\"shipping_method_0_flat_rate3\">ঢাকার বাহিরে: <bdi>130&#2547;&nbsp;</bdi></label>					</li>\n							</ul>\n			</td>\n</tr>\n		<tr>\n			<th>Total</th>\n			<td><strong><bdi>1,420&#2547;&nbsp;</bdi></strong> </td>\n		</tr>\n	</tfoot>\n</table>\n						<input type=\"text\" name=\"coupon_code\" placeholder=\"Coupon Code\" id=\"coupon_code\" value=\"\">\n						<button type=\"button\" name=\"apply_coupon\" value=\"Apply\">Apply</button>\n			<ul>\n			<li>\n	<input id=\"payment_method_cod\" type=\"radio\" name=\"payment_method\" value=\"cod\"  checked=\'checked\' data-order_button_text=\"\" />\n	<label for=\"payment_method_cod\">\n		ক্যাশ অন ডেলিভারি 	</label>\n			<p>প্রোডাক্ট হাতে পেয়ে মূল্য পরিশোধ করুন</p>\n	</li>\n		</ul>\n		<noscript>\n			Since your browser does not support JavaScript, or it is disabled, please ensure you click the <em>Update Totals</em> button before placing your order. You may be charged more than the amount stated above if you fail to do so.			<br/><button type=\"submit\" name=\"woocommerce_checkout_update_totals\" value=\"Update totals\">Update totals</button>\n		</noscript>\n		<p>Your personal data will be used to process your order, support your experience throughout this website, and for other purposes described in our <a href=\"https://ninetys.store/?page_id=3\" target=\"_blank\">privacy policy</a>.</p>\n		<button type=\"submit\" name=\"woocommerce_checkout_place_order\" id=\"place_order\" value=\"অর্ডার করুন&nbsp;&nbsp;1,420&#2547;&nbsp;\" data-value=\"অর্ডার করুন&nbsp;&nbsp;1,420&#2547;&nbsp;\">অর্ডার করুন&nbsp;&nbsp;1,420&#2547;&nbsp;</button>\n		<input type=\"hidden\" id=\"woocommerce-process-checkout-nonce\" name=\"woocommerce-process-checkout-nonce\" value=\"b67b40de1c\" /><input type=\"hidden\" name=\"_wp_http_referer\" value=\"/wp-admin/admin-ajax.php\" />	\n</form>\n<!-- END CHECKOUT SHORTCODE -->\n		<p>Copyright © 2024 Your Business Name | This website made with ❤️ by <a style=\"color: red; font-weight: bold;\" href=\"https://digiprodwave.xyz\">DPW</a></p>', 'Store Checkout 02', '', 'publish', 'closed', 'closed', '', 'store-checkout-02', '', '', '2026-06-27 22:03:36', '2026-06-27 22:03:36', '', 0, 'https://ninetys.store/step/store-checkout-02/', 0, 'cartflows_step', '', 0),
