ue=\"1\" step=\"1\" min=\"1\" name=\"wcf_qty_selection\" placeholder=\"1\" data-sale-limit=\"false\"  title=\"\"  >\n		&plus;\n	1,290&#2547;&nbsp;\n				<wc-order-attribution-inputs></wc-order-attribution-inputs>\n		<h3 id=\"billing_fields_heading\">Billing details</h3>\n		<p id=\"billing_first_name_field\" data-priority=\"10\"><label for=\"billing_first_name\">Full Name&nbsp;*</label><input type=\"text\" name=\"billing_first_name\" id=\"billing_first_name\" placeholder=\"আপনার নাম\"  value=\"\" aria-required=\"true\" autocomplete=\"section-billing billing given-name\" /></p><p id=\"billing_address_1_field\" data-priority=\"40\"><label for=\"billing_address_1\">Full Address&nbsp;*</label><input type=\"text\" name=\"billing_address_1\" id=\"billing_address_1\" placeholder=\"আপনার ঠিকানা\"  value=\"\" aria-required=\"true\" autocomplete=\"section-billing billing address-line1\" /></p><p id=\"billing_phone_field\" data-priority=\"90\"><label for=\"billing_phone\">Phone Number&nbsp;*</label><input type=\"tel\" name=\"billing_phone\" id=\"billing_phone\" placeholder=\"আপনার নাম্বার\"  value=\"\" aria-required=\"true\" autocomplete=\"section-billing billing tel\" /></p><p id=\"billing_whatsapp_field\" data-priority=\"100\"><label for=\"billing_whatsapp\">WhatsApp&nbsp;*</label><textarea name=\"billing_whatsapp\" id=\"billing_whatsapp\" placeholder=\"আপনার হোয়াটসঅ্যাপ\"  rows=\"2\" cols=\"5\"aria-required=\"true\"></textarea></p><p id=\"billing_email_field\" data-priority=\"110\"><label for=\"billing_email\">Email address&nbsp;*</label><input type=\"email\" name=\"billing_email\" id=\"billing_email\" placeholder=\"আপনার ইমেইল\"  value=\"admin@ninetys.store\" aria-required=\"true\" autocomplete=\"section-billing billing email\" /></p>	\n	<wc-order-attribution-inputs></wc-order-attribution-inputs>\n				<wc-order-attribution-inputs></wc-order-attribution-inputs>\n	<wc-order-attribution-inputs></wc-order-attribution-inputs><input type=\"hidden\" name=\"_wcf_flow_id\" value=\"38\"><input type=\"hidden\" name=\"_wcf_checkout_id\" value=\"39\">\n		<wc-order-attribution-inputs></wc-order-attribution-inputs>\n		<h3>Shipping</h3>\n							<ul id=\"shipping_method\">\n											<li>\n							<input type=\"radio\" name=\"shipping_method[0]\" data-index=\"0\" id=\"wcf_shipping_method_0_flat_rate2\" value=\"flat_rate:2\"  /><label for=\"wcf_shipping_method_0_flat_rate2\">ঢাকার ভিতরে: <bdi>80&#2547;&nbsp;</bdi></label>						</li>\n											<li>\n							<input type=\"radio\" name=\"shipping_method[0]\" data-index=\"0\" id=\"wcf_shipping_method_0_flat_rate3\" value=\"flat_rate:3\"  checked=\'checked\' /><label for=\"wcf_shipping_method_0_flat_rate3\">ঢাকার বাহিরে: <bdi>130&#2547;&nbsp;</bdi></label>						</li>\n									</ul>\n		<h3 id=\"order_review_heading\">Your order</h3>\n			<table data-update-time=\"1782597816\">\n	<thead>\n		<tr>\n			<th>Product</th>\n			<th>Subtotal</th>\n		</tr>\n	</thead>\n	<tbody>\n						<tr>\n					<td>\n						Saree Combo - Merun&nbsp;						 <strong>&times;&nbsp;1</strong>											</td>\n					<td>\n						<bdi>1,290&#2547;&nbsp;</bdi>					</td>\n				</tr>\n					</tbody>\n	<tfoot>\n				<tr>\n			<th>Subtotal</th>\n			<td><bdi>1,290&#2547;&nbsp;</bdi></td>\n		</tr>\n						<tr>\n	<th>Shipment</th>\n	<td data-title=\"Shipment\">\n					<ul id=\"shipping_method\">\n									<li>\n						<input type=\"radio\" name=\"shipping_method[0]\" data-index=\"0\" id=\"shipping_method_0_flat_rate2\" value=\"flat_rate:2\"  /><label for=\"shipping_method_0_flat_rate2\">ঢাকার ভিতরে: <bdi>80&#2547;&nbsp;</bdi></label>					</li>\n									<li>\n						<input type=\"radio\" name=\"shipping_method[0]\" data-index=\"0\" id=\"shipping_method_0_flat_rate3\" value=\"flat_rate:3\"  checked=\'checked\' /><label for=\"shipping_method_0_flat_rate3\">ঢাকার বাহিরে: <bdi>130&#2547;&nbsp;</bdi></label>					</li>\n							</ul>\n			</td>\n</tr>\n		<tr>\n			<th>Total</th>\n			<td><strong><bdi>1,420&#2547;&nbsp;</bdi></strong> </td>\n		</tr>\n	</tfoot>\n</table>\n						<input type=\"text\" name=\"coupon_code\" placeholder=\"Coupon Code\" id=\"coupon_code\" value=\"\">\n						<button type=\"button\" name=\"apply_coupon\" value=\"Apply\">Apply</button>\n			<ul>\n			<li>\n	<input id=\"payment_method_cod\" type=\"radio\" name=\"payment_method\" value=\"cod\"  checked=\'checked\' data-order_button_text=\"\" />\n	<label for=\"payment_method_cod\">\n		ক্যাশ অন ডেলিভারি 	</label>\n			<p>প্রোডাক্ট হাতে পেয়ে মূল্য পরিশোধ করুন</p>\n	</li>\n		</ul>\n		<noscript>\n			Since your browser does not support JavaScript, or it is disabled, please ensure you click the <em>Update Totals</em> button before placing your order. You may be charged more than the amount stated above if you fail to do so.			<br/><button type=\"submit\" name=\"woocommerce_checkout_update_totals\" value=\"Update totals\">Update totals</button>\n		</noscript>\n		<p>Your personal data will be used to process your order, support your experience throughout this website, and for other purposes described in our <a href=\"https://ninetys.store/?page_id=3\" target=\"_blank\">privacy policy</a>.</p>\n		<button type=\"submit\" name=\"woocommerce_checkout_place_order\" id=\"place_order\" value=\"অর্ডার করুন&nbsp;&nbsp;1,420&#2547;&nbsp;\" data-value=\"অর্ডার করুন&nbsp;&nbsp;1,420&#2547;&nbsp;\">অর্ডার করুন&nbsp;&nbsp;1,420&#2547;&nbsp;</button>\n		<input type=\"hidden\" id=\"woocommerce-process-checkout-nonce\" name=\"woocommerce-process-checkout-nonce\" value=\"b67b40de1c\" /><input type=\"hidden\" name=\"_wp_http_referer\" value=\"/wp-admin/admin-ajax.php\" />	\n</form>\n<!-- END CHECKOUT SHORTCODE -->\n		<p>Copyright © 2024 Your Business Name | This website made with ❤️ by <a style=\"color: red; font-weight: bold;\" href=\"https://digiprodwave.xyz\">DPW</a></p>', 'Store Checkout 02', '', 'inherit', 'closed', 'closed', '', '39-revision-v1', '', '', '2026-06-27 22:03:36', '2026-06-27 22:03:36', '', 39, 'https://ninetys.store/?p=51', 0, 'revision', '', 0),
